#include<bits/stdc++.h>
using namespace std;
long long n,a[600010];
struct st
{
    long long lg[600010];
    long long f[600010][22];
    void init()
    {
        lg[1]=0;
        for(long long i=2;i<=n;i++)
        {
            lg[i]=lg[i/2]+1;
        }
        for(long long i=1;i<=n;i++)
        {
            f[i][0]=a[i];
        }
        for(long long j=1;j<=lg[n];j++)
        {
            for(long long i=1;i<=n-(1<<j)+1;i++)
            {
                f[i][j]=gcd(f[i][j-1],f[i+(1<<(j-1))][j-1]);
            }
        }
    }
    long long getgcd(long long l,long long r)
    {
        long long temp=lg[r-l+1];
        return gcd(f[l][temp],f[r-(1<<temp)+1][temp]);
    }
}t;
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    t.init();
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        long long l=1,r=(n-i)/2+1;
        long long best=-1;
        while(l<=r)
        {
            long long mid=(l+r)>>1;
            long long pos=(mid-1)*2+i;
            if(t.getgcd(i,pos)%3!=0)
            {
                r=mid-1;
            }
            else if(t.getgcd(i,pos)%3==0)
            {
                best=max(best,pos);
                l=mid+1;
            }
            else
            {
                l=mid+1;
            }
        }
        long long best2=1e9;
        if(best!=-1)
        {
            long long l=1,r=(best-i)/2+1;
            while(l<=r)
            {
                long long mid=(l+r)>>1;
                long long pos=(mid-1)*2+i;
                if(t.getgcd(i,pos)==3)
                {
                    best2=min(best2,pos);
                    r=mid-1;
                }
                else
                {
                    l=mid+1;
                }
            }
        }
        if(best!=-1&&best2!=1e9)
        {
            ans+=(best+best2-i*2+2)*((best-best2)/2+1)/2;
        }
        l=1,r=(n-i+1)/2;
        best=-1;
        while(l<=r)
        {
            long long mid=(l+r)>>1;
            long long pos=mid*2+i-1;
            if(t.getgcd(i,pos)%2!=0)
            {
                r=mid-1;
            }
            else if(t.getgcd(i,pos)%2==0)
            {
                best=max(best,pos);
                l=mid+1;
            }
            else
            {
                l=mid+1;
            }
        }
        best2=1e9;
        if(best!=-1)
        {
            long long l=1,r=(best-i+1)/2;
            while(l<=r)
            {
                long long mid=(l+r)>>1;
                long long pos=mid*2+i-1;
                if(t.getgcd(i,pos)==2)
                {
                    best2=min(best2,pos);
                    r=mid-1;
                }
                else
                {
                    l=mid+1;
                }
            }
        }
        if(best!=-1&&best2!=1e9)
        {
            ans+=(best+best2-i*2+2)*((best-best2)/2+1)/2;
        }
    }
    printf("%lld",ans);
    return 0;
}
